@startuml
skinparam classAttributeIconSize 0

class User {
  String userName
  String password
}

class Tenant {
  String name
}

class Cloud {
  String endpoint
}

class Api {
  String driver
}

class CloudCredential {
  String userName
  String secret
}

abstract class Resource {
  String id
  String name
}

class Image {
  String id
  String name
}

class Hardware {
  String id
  String name
  int cores
  int ram
  int disk
}

class Location {
  String id
  String name
  boolean isAssignable
}

class OperatingSystem {
}

class HardwareOffer {
}

class GeoLocation {
}

enum LocationScope {
  REGION,
  ZONe,
  HOST
}

' Layout to match the diagram (no relationships shown)
User -[hidden]- Tenant
Tenant -[hidden]- Cloud
Cloud -[hidden]- Api

CloudCredential -[hidden]- Resource
Resource -[hidden]- Image
Image -[hidden]- Hardware

Location -[hidden]- OperatingSystem
OperatingSystem -[hidden]- HardwareOffer
HardwareOffer -[hidden]- GeoLocation

LocationScope -[hidden]- Location
@enduml
